    var res: seq<int> := [];

    for i := 0 to a.Length
        invariant 0 <= i <= a.Length
        invariant forall x :: x in res ==> (InArray(a, x) && InArray(b, x))
        invariant forall x :: x in res ==> (InArray(a, x) && InArray(b, x))
        invariant forall i, j :: 0 <= i < j < |res| ==> res[i] != res[j]
    {
        var x := a[i];
        if InArray(b, x) && x !in res
        {
